  1→import React, { createContext, useContext, useEffect, useState, useCallback, type ReactNode } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { setExternalUserId, removeExternalUserId } from '../lib/onesignal';
  4→import type { Profile } from '@astrolab/shared';
  5→import type { User, Session } from '@supabase/supabase-js';
  6→
  7→interface AuthContextValue {
  8→  user: User | null;
  9→  profile: Profile | null;
 10→  session: Session | null;
 11→  loading: boolean;
 12→  signIn: (email: string, password: string) => Promise<{ error: string | null }>;
 13→  signUp: (email: string, password: string, fullName: string) => Promise<{ error: string | null }>;
 14→  signOut: () => Promise<void>;
 15→  resetPassword: (email: string) => Promise<{ error: string | null }>;
 16→  isAuthenticated: boolean;
 17→}
 18→
 19→const AuthContext = createContext<AuthContextValue | null>(null);
 20→
 21→export function AuthProvider({ children }: { children: ReactNode }) {
 22→  const [user, setUser] = useState<User | null>(null);
 23→  const [profile, setProfile] = useState<Profile | null>(null);
 24→  const [session, setSession] = useState<Session | null>(null);
 25→  const [loading, setLoading] = useState(true);
 26→
 27→  const fetchProfile = useCallback(async (userId: string) => {
 28→    const { data } = await supabase
 29→      .from('profiles')
 30→      .select('*')
 31→      .eq('id', userId)
 32→      .single();
 33→    setProfile(data as Profile | null);
 34→    if (data) {
 35→      setExternalUserId(data.id);
 36→    }
 37→  }, []);
 38→
 39→  useEffect(() => {
 40→    supabase.auth.getSession().then(({ data: { session: s } }) => {
 41→      setSession(s);
 42→      setUser(s?.user ?? null);
 43→      if (s?.user) {
 44→        fetchProfile(s.user.id).finally(() => setLoading(false));
 45→      } else {
 46→        setLoading(false);
 47→      }
 48→    });
 49→
 50→    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, s) => {
 51→      setSession(s);
 52→      setUser(s?.user ?? null);
 53→      if (s?.user) {
 54→        fetchProfile(s.user.id);
 55→      } else {
 56→        setProfile(null);
 57→      }
 58→    });
 59→
 60→    return () => subscription.unsubscribe();
 61→  }, [fetchProfile]);
 62→
 63→  const signIn = async (email: string, password: string) => {
 64→    const { error } = await supabase.auth.signInWithPassword({ email, password });
 65→    return { error: error?.message ?? null };
 66→  };
 67→
 68→  const signUp = async (email: string, password: string, fullName: string) => {
 69→    const { error } = await supabase.auth.signUp({
 70→      email,
 71→      password,
 72→      options: {
 73→        data: { role: 'customer', full_name: fullName },
 74→      },
 75→    });
 76→    return { error: error?.message ?? null };
 77→  };
 78→
 79→  const signOut = async () => {
 80→    removeExternalUserId();
 81→    await supabase.auth.signOut();
 82→    setUser(null);
 83→    setProfile(null);
 84→    setSession(null);
 85→  };
 86→
 87→  const resetPassword = async (email: string) => {
 88→    const { error } = await supabase.auth.resetPasswordForEmail(email, {
 89→      redirectTo: 'astrolab://reset-password',
 90→    });
 91→    return { error: error?.message ?? null };
 92→  };
 93→
 94→  return (
 95→    <AuthContext.Provider
 96→      value={{
 97→        user,
 98→        profile,
 99→        session,
100→        loading,
101→        signIn,
102→        signUp,
103→        signOut,
104→        resetPassword,
105→        isAuthenticated: !!user && !!profile,
106→      }}
107→    >
108→      {children}
109→    </AuthContext.Provider>
110→  );
111→}
112→
113→export function useAuth() {
114→  const ctx = useContext(AuthContext);
115→  if (!ctx) {
116→    throw new Error('useAuth must be used within AuthProvider');
117→  }
118→  return ctx;
119→}
