 1→import React, { createContext, useContext, useEffect, useState, type ReactNode } from 'react';
 2→import { Platform } from 'react-native';
 3→import { useAuth } from './AuthContext';
 4→import { initOneSignal, getPlayerId } from '../lib/onesignal';
 5→import { supabase } from '../lib/supabase';
 6→
 7→interface PushContextValue {
 8→  pushEnabled: boolean;
 9→  playerId: string | null;
10→}
11→
12→const PushContext = createContext<PushContextValue>({
13→  pushEnabled: false,
14→  playerId: null,
15→});
16→
17→export function PushProvider({ children }: { children: ReactNode }) {
18→  const { profile } = useAuth();
19→  const [playerId, setPlayerId] = useState<string | null>(null);
20→  const [pushEnabled, setPushEnabled] = useState(false);
21→
22→  useEffect(() => {
23→    initOneSignal();
24→  }, []);
25→
26→  useEffect(() => {
27→    if (!profile) return;
28→
29→    const registerPlayer = async () => {
30→      const id = await getPlayerId();
31→      if (!id) return;
32→
33→      setPlayerId(id);
34→      setPushEnabled(true);
35→
36→      // Register in onesignal_subscriptions table
37→      const deviceType = Platform.OS === 'ios' ? 'ios' : 'android';
38→
39→      await supabase.from('onesignal_subscriptions').upsert(
40→        {
41→          profile_id: profile.id,
42→          player_id: id,
43→          device_type: deviceType,
44→          is_active: true,
45→        },
46→        { onConflict: 'profile_id,player_id' }
47→      );
48→    };
49→
50→    // Small delay to let OneSignal initialize
51→    const timer = setTimeout(registerPlayer, 2000);
52→    return () => clearTimeout(timer);
53→  }, [profile]);
54→
55→  return (
56→    <PushContext.Provider value={{ pushEnabled, playerId }}>
57→      {children}
58→    </PushContext.Provider>
59→  );
60→}
61→
62→export function usePush() {
63→  return useContext(PushContext);
