 1→import { useState, useEffect } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import { useAuth } from './useAuth';
 4→import type { QRCode } from '@astrolab/shared';
 5→
 6→interface UseCounterQRReturn {
 7→  qrCode: QRCode | null;
 8→  qrUrl: string | null;
 9→  loading: boolean;
10→  error: string | null;
11→}
12→
13→export function useCounterQR(): UseCounterQRReturn {
14→  const { user } = useAuth();
15→  const [qrCode, setQrCode] = useState<QRCode | null>(null);
16→  const [loading, setLoading] = useState(true);
17→  const [error, setError] = useState<string | null>(null);
18→
19→  useEffect(() => {
20→    if (!user) {
21→      setLoading(false);
22→      return;
23→    }
24→
25→    async function fetchCounterQR() {
26→      // Recuperer le merchant_id depuis le profil
27→      const { data: merchant, error: merchantError } = await supabase
28→        .from('merchants')
29→        .select('id')
30→        .eq('profile_id', user!.id)
31→        .single();
32→
33→      if (merchantError || !merchant) {
34→        setError('Profil marchand introuvable');
35→        setLoading(false);
36→        return;
37→      }
38→
39→      // Recuperer le QR comptoir existant
40→      let { data: qr } = await supabase
41→        .from('qr_codes')
42→        .select('*')
43→        .eq('merchant_id', merchant.id)
44→        .eq('qr_type', 'counter')
45→        .eq('is_active', true)
46→        .maybeSingle();
47→
48→      // Si pas de QR comptoir, en creer un (fallback si trigger n'a pas ete applique)
49→      if (!qr) {
50→        const { data: newQr, error: insertError } = await supabase
51→          .from('qr_codes')
52→          .insert({
53→            merchant_id: merchant.id,
54→            qr_type: 'counter' as const,
55→            token: crypto.randomUUID().replace(/-/g, ''),
56→            max_uses: 2147483647,
57→            is_active: true,
58→          })
59→          .select()
60→          .single();
61→
62→        if (insertError) {
63→          setError('Impossible de creer le QR comptoir');
64→          setLoading(false);
65→          return;
66→        }
67→        qr = newQr;
68→      }
69→
70→      setQrCode(qr as QRCode);
71→      setLoading(false);
72→    }
73→
74→    fetchCounterQR();
75→  }, [user]);
76→
77→  const appUrl = import.meta.env.VITE_APP_URL || window.location.origin;
78→  const qrUrl = qrCode ? `${appUrl}/scan/${qrCode.token}` : null;
79→
80→  return { qrCode, qrUrl, loading, error };
81→}
