  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { CampaignWithStats, CampaignStatus } from '@astrolab/shared';
  5→
  6→const PAGE_SIZE = 10;
  7→
  8→type FilterStatus = 'all' | CampaignStatus;
  9→
 10→export function useMerchantCampaigns() {
 11→  const { profile } = useAuth();
 12→  const [campaigns, setCampaigns] = useState<CampaignWithStats[]>([]);
 13→  const [totalCount, setTotalCount] = useState(0);
 14→  const [loading, setLoading] = useState(true);
 15→  const [error, setError] = useState<string | null>(null);
 16→  const [filter, setFilter] = useState<FilterStatus>('all');
 17→  const [page, setPage] = useState(1);
 18→
 19→  const fetchCampaigns = useCallback(async () => {
 20→    if (!profile) return;
 21→
 22→    setLoading(true);
 23→    setError(null);
 24→
 25→    try {
 26→      // Get merchant_id
 27→      const { data: merchant } = await supabase
 28→        .from('merchants')
 29→        .select('id')
 30→        .eq('profile_id', profile.id)
 31→        .single();
 32→
 33→      if (!merchant) {
 34→        setError('Profil marchand introuvable');
 35→        setLoading(false);
 36→        return;
 37→      }
 38→
 39→      let query = supabase
 40→        .from('campaigns')
 41→        .select('*', { count: 'exact' })
 42→        .eq('merchant_id', merchant.id)
 43→        .order('created_at', { ascending: false });
 44→
 45→      if (filter !== 'all') {
 46→        query = query.eq('status', filter);
 47→      }
 48→
 49→      const from = (page - 1) * PAGE_SIZE;
 50→      const to = from + PAGE_SIZE - 1;
 51→      query = query.range(from, to);
 52→
 53→      const { data, error: fetchError, count } = await query;
 54→
 55→      if (fetchError) {
 56→        setError(fetchError.message);
 57→        setLoading(false);
 58→        return;
 59→      }
 60→
 61→      const enriched: CampaignWithStats[] = (data ?? []).map((c) => ({
 62→        ...c,
 63→        conversion_rate:
 64→          c.total_sent > 0
 65→            ? Math.round((c.total_redeemed / c.total_sent) * 1000) / 10
 66→            : 0,
 67→      }));
 68→
 69→      setCampaigns(enriched);
 70→      setTotalCount(count ?? 0);
 71→    } catch {
 72→      setError('Erreur de chargement');
 73→    } finally {
 74→      setLoading(false);
 75→    }
 76→  }, [profile, filter, page]);
 77→
 78→  useEffect(() => {
 79→    fetchCampaigns();
 80→  }, [fetchCampaigns]);
 81→
 82→  const totalPages = Math.ceil(totalCount / PAGE_SIZE);
 83→
 84→  return {
 85→    campaigns,
 86→    totalCount,
 87→    loading,
 88→    error,
 89→    filter,
 90→    setFilter: (f: FilterStatus) => {
 91→      setFilter(f);
 92→      setPage(1);
 93→    },
 94→    page,
 95→    totalPages,
 96→    nextPage: () => setPage((p) => Math.min(p + 1, totalPages)),
 97→    prevPage: () => setPage((p) => Math.max(p - 1, 1)),
 98→    setPage,
 99→    refetch: fetchCampaigns,
100→  };
101→}
