  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { Campaign, CampaignClientRow } from '@astrolab/shared';
  5→
  6→interface CampaignStats {
  7→  total_sent: number;
  8→  total_redeemed: number;
  9→  conversion_rate: number;
 10→  pending: number;
 11→}
 12→
 13→interface DailyRedemption {
 14→  date: string;
 15→  count: number;
 16→}
 17→
 18→export function useCampaignDetail(campaignId: string | undefined) {
 19→  const { profile } = useAuth();
 20→  const [campaign, setCampaign] = useState<Campaign | null>(null);
 21→  const [stats, setStats] = useState<CampaignStats>({
 22→    total_sent: 0,
 23→    total_redeemed: 0,
 24→    conversion_rate: 0,
 25→    pending: 0,
 26→  });
 27→  const [clients, setClients] = useState<CampaignClientRow[]>([]);
 28→  const [chartData, setChartData] = useState<DailyRedemption[]>([]);
 29→  const [loading, setLoading] = useState(true);
 30→  const [error, setError] = useState<string | null>(null);
 31→
 32→  const fetchDetail = useCallback(async () => {
 33→    if (!profile || !campaignId) return;
 34→
 35→    setLoading(true);
 36→    setError(null);
 37→
 38→    try {
 39→      // Get merchant_id
 40→      const { data: merchant } = await supabase
 41→        .from('merchants')
 42→        .select('id')
 43→        .eq('profile_id', profile.id)
 44→        .single();
 45→
 46→      if (!merchant) {
 47→        setError('Profil marchand introuvable');
 48→        setLoading(false);
 49→        return;
 50→      }
 51→
 52→      // Get campaign
 53→      const { data: campaignData, error: campaignError } = await supabase
 54→        .from('campaigns')
 55→        .select('*')
 56→        .eq('id', campaignId)
 57→        .eq('merchant_id', merchant.id)
 58→        .single();
 59→
 60→      if (campaignError || !campaignData) {
 61→        setError('Campagne introuvable');
 62→        setLoading(false);
 63→        return;
 64→      }
 65→
 66→      setCampaign(campaignData);
 67→
 68→      // Compute stats
 69→      const convRate = campaignData.total_sent > 0
 70→        ? Math.round((campaignData.total_redeemed / campaignData.total_sent) * 1000) / 10
 71→        : 0;
 72→
 73→      setStats({
 74→        total_sent: campaignData.total_sent,
 75→        total_redeemed: campaignData.total_redeemed,
 76→        conversion_rate: convRate,
 77→        pending: campaignData.total_sent - campaignData.total_redeemed,
 78→      });
 79→
 80→      // Get QR codes for this campaign with customer info
 81→      const { data: qrCodes } = await supabase
 82→        .from('qr_codes')
 83→        .select(`
 84→          token,
 85→          customer_id,
 86→          is_active,
 87→          expires_at,
 88→          uses_count,
 89→          customers!inner (
 90→            id,
 91→            profile_id,
 92→            profiles!inner (
 93→              full_name,
 94→              email
 95→            )
 96→          )
 97→        `)
 98→        .eq('campaign_id', campaignId)
 99→        .eq('qr_type', 'campaign');
100→
101→      // Get redemptions for this campaign
102→      const { data: redemptions } = await supabase
103→        .from('campaign_redemptions')
104→        .select('customer_id, redeemed_at')
105→        .eq('campaign_id', campaignId);
106→
107→      const redemptionMap = new Map<string, string>();
108→      (redemptions ?? []).forEach((r) => {
109→        redemptionMap.set(r.customer_id, r.redeemed_at);
110→      });
111→
112→      // Build client rows
113→      const clientRows: CampaignClientRow[] = (qrCodes ?? []).map((qr) => {
114→        const customer = qr.customers as unknown as {
115→          id: string;
116→          profile_id: string;
117→          profiles: { full_name: string | null; email: string };
118→        };
119→
120→        const redeemed = redemptionMap.get(qr.customer_id!);
121→        let qrStatus: 'active' | 'expired' | 'used' = 'active';
122→
123→        if (redeemed || qr.uses_count > 0) {
124→          qrStatus = 'used';
125→        } else if (!qr.is_active || (qr.expires_at && new Date(qr.expires_at) < new Date())) {
126→          qrStatus = 'expired';
127→        }
128→
129→        return {
130→          customer_id: qr.customer_id!,
131→          full_name: customer.profiles.full_name || 'Sans nom',
132→          email: customer.profiles.email,
133→          qr_token: qr.token,
134→          qr_status: qrStatus,
135→          redeemed_at: redeemed || null,
136→        };
137→      });
138→
139→      setClients(clientRows);
140→
141→      // Build chart data (redemptions per day)
142→      const dailyMap = new Map<string, number>();
143→      (redemptions ?? []).forEach((r) => {
144→        const day = r.redeemed_at.slice(0, 10);
145→        dailyMap.set(day, (dailyMap.get(day) || 0) + 1);
146→      });
147→
148→      const sortedDays = Array.from(dailyMap.entries())
149→        .sort(([a], [b]) => a.localeCompare(b))
150→        .map(([date, count]) => ({ date, count }));
151→
152→      setChartData(sortedDays);
153→    } catch {
154→      setError('Erreur de chargement');
155→    } finally {
156→      setLoading(false);
157→    }
158→  }, [profile, campaignId]);
159→
160→  useEffect(() => {
161→    fetchDetail();
162→  }, [fetchDetail]);
163→
164→  return {
165→    campaign,
166→    stats,
167→    clients,
168→    chartData,
169→    loading,
170→    error,
171→    refetch: fetchDetail,
172→  };
173→}
