  1→import { useEffect, useState, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { BillingEvent, SubscriptionInfo } from '@astrolab/shared';
  5→
  6→export function useBilling() {
  7→  const { profile } = useAuth();
  8→  const [subscription, setSubscription] = useState<SubscriptionInfo>({
  9→    status: 'trial',
 10→    plan: 'starter',
 11→    trialEndsAt: null,
 12→    trialDaysRemaining: null,
 13→    hadTrial: false,
 14→    stripeCustomerId: null,
 15→  });
 16→  const [billingHistory, setBillingHistory] = useState<BillingEvent[]>([]);
 17→  const [loading, setLoading] = useState(true);
 18→  const [error, setError] = useState<string | null>(null);
 19→
 20→  const fetchBilling = useCallback(async () => {
 21→    if (!profile) return;
 22→
 23→    setLoading(true);
 24→    setError(null);
 25→
 26→    try {
 27→      const { data: merchant } = await supabase
 28→        .from('merchants')
 29→        .select(
 30→          'id, subscription_status, subscription_plan, trial_ends_at, had_trial, stripe_customer_id'
 31→        )
 32→        .eq('profile_id', profile.id)
 33→        .single();
 34→
 35→      if (!merchant) {
 36→        setLoading(false);
 37→        return;
 38→      }
 39→
 40→      // Calculate trial days remaining
 41→      let trialDaysRemaining: number | null = null;
 42→      if (
 43→        merchant.subscription_status === 'trial' &&
 44→        merchant.trial_ends_at
 45→      ) {
 46→        const now = new Date();
 47→        const trialEnd = new Date(merchant.trial_ends_at);
 48→        const diff = trialEnd.getTime() - now.getTime();
 49→        trialDaysRemaining = Math.max(0, Math.ceil(diff / (1000 * 60 * 60 * 24)));
 50→      }
 51→
 52→      setSubscription({
 53→        status: merchant.subscription_status as SubscriptionInfo['status'],
 54→        plan: (merchant.subscription_plan || 'starter') as SubscriptionInfo['plan'],
 55→        trialEndsAt: merchant.trial_ends_at,
 56→        trialDaysRemaining,
 57→        hadTrial: merchant.had_trial || false,
 58→        stripeCustomerId: merchant.stripe_customer_id,
 59→      });
 60→
 61→      // Fetch billing history
 62→      const { data: events } = await supabase
 63→        .from('billing_events')
 64→        .select('*')
 65→        .eq('merchant_id', merchant.id)
 66→        .order('created_at', { ascending: false })
 67→        .limit(20);
 68→
 69→      setBillingHistory((events as BillingEvent[]) || []);
 70→    } catch (err) {
 71→      setError(err instanceof Error ? err.message : 'Erreur inconnue');
 72→    } finally {
 73→      setLoading(false);
 74→    }
 75→  }, [profile]);
 76→
 77→  useEffect(() => {
 78→    fetchBilling();
 79→  }, [fetchBilling]);
 80→
 81→  // Create Stripe Checkout session
 82→  const createCheckout = async (plan: string): Promise<string> => {
 83→    const {
 84→      data: { session },
 85→    } = await supabase.auth.getSession();
 86→
 87→    const res = await fetch(
 88→      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-checkout-session`,
 89→      {
 90→        method: 'POST',
 91→        headers: {
 92→          'Content-Type': 'application/json',
 93→          Authorization: `Bearer ${session?.access_token}`,
 94→        },
 95→        body: JSON.stringify({ plan }),
 96→      }
 97→    );
 98→
 99→    const result = await res.json();
100→    if (!result.success) {
101→      throw new Error(result.error?.message || 'Erreur lors de la creation du checkout');
102→    }
103→
104→    return result.data.checkout_url;
105→  };
106→
107→  // Open Stripe Customer Portal
108→  const openPortal = async (): Promise<string> => {
109→    const {
110→      data: { session },
111→    } = await supabase.auth.getSession();
112→
113→    const res = await fetch(
114→      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/create-portal-session`,
115→      {
116→        method: 'POST',
117→        headers: {
118→          'Content-Type': 'application/json',
119→          Authorization: `Bearer ${session?.access_token}`,
120→        },
121→        body: JSON.stringify({}),
122→      }
123→    );
124→
125→    const result = await res.json();
126→    if (!result.success) {
127→      throw new Error(result.error?.message || 'Erreur lors de l\'ouverture du portail');
128→    }
129→
130→    return result.data.portal_url;
131→  };
132→
133→  // Check if a feature is available for the current plan
134→  const isFeatureAvailable = (feature: string): boolean => {
135→    if (
136→      subscription.status === 'cancelled' ||
137→      subscription.status === 'past_due'
138→    ) {
139→      // Cancelled/past_due: only read access
140→      const readOnlyFeatures = ['view_dashboard', 'view_clients', 'view_history'];
141→      return readOnlyFeatures.includes(feature);
142→    }
143→
144→    const FEATURE_PLANS: Record<string, string[]> = {
145→      create_campaign: ['starter', 'pro', 'business'],
146→      schedule_campaign: ['pro', 'business'],
147→      ai_suggestions: ['pro', 'business'],
148→      automations: ['pro', 'business'],
149→      weekly_reports: ['pro', 'business'],
150→      advanced_analytics: ['business'],
151→      multi_location: ['business'],
152→      api_access: ['business'],
153→      export_data: ['business'],
154→      unlimited_clients: ['pro', 'business'],
155→    };
156→
157→    const allowedPlans = FEATURE_PLANS[feature];
158→    if (!allowedPlans) return true; // unknown features are allowed
159→
160→    // During trial, grant Pro access
161→    if (subscription.status === 'trial') {
162→      const trialPlans = FEATURE_PLANS[feature];
163→      return trialPlans
164→        ? trialPlans.includes('pro') || trialPlans.includes('starter')
165→        : true;
166→    }
167→
168→    return allowedPlans.includes(subscription.plan);
169→  };
170→
171→  return {
172→    subscription,
173→    billingHistory,
174→    loading,
175→    error,
176→    createCheckout,
177→    openPortal,
178→    isFeatureAvailable,
179→    refetch: fetchBilling,
180→  };
181→}
