  1→import { useEffect, useState, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { AICampaignSuggestion } from '@astrolab/shared';
  5→
  6→export function useAISuggestions() {
  7→  const { profile } = useAuth();
  8→  const [suggestions, setSuggestions] = useState<AICampaignSuggestion[]>([]);
  9→  const [loading, setLoading] = useState(true);
 10→  const [error, setError] = useState<string | null>(null);
 11→
 12→  const fetchSuggestions = useCallback(async () => {
 13→    if (!profile) return;
 14→
 15→    setLoading(true);
 16→    setError(null);
 17→
 18→    try {
 19→      const { data: merchant } = await supabase
 20→        .from('merchants')
 21→        .select('id')
 22→        .eq('profile_id', profile.id)
 23→        .single();
 24→
 25→      if (!merchant) {
 26→        setLoading(false);
 27→        return;
 28→      }
 29→
 30→      const { data, error: fetchError } = await supabase
 31→        .from('ai_campaign_suggestions')
 32→        .select('*')
 33→        .eq('merchant_id', merchant.id)
 34→        .order('created_at', { ascending: false });
 35→
 36→      if (fetchError) throw fetchError;
 37→      setSuggestions((data as AICampaignSuggestion[]) || []);
 38→    } catch (err) {
 39→      setError(err instanceof Error ? err.message : 'Erreur inconnue');
 40→    } finally {
 41→      setLoading(false);
 42→    }
 43→  }, [profile]);
 44→
 45→  useEffect(() => {
 46→    fetchSuggestions();
 47→  }, [fetchSuggestions]);
 48→
 49→  const pendingSuggestions = suggestions.filter((s) => s.status === 'pending');
 50→
 51→  const acceptSuggestion = async (id: string) => {
 52→    const suggestion = suggestions.find((s) => s.id === id);
 53→    if (!suggestion) return null;
 54→
 55→    // Mark as accepted
 56→    await supabase
 57→      .from('ai_campaign_suggestions')
 58→      .update({ status: 'accepted' })
 59→      .eq('id', id);
 60→
 61→    // Create draft campaign from suggestion
 62→    const { data: merchant } = await supabase
 63→      .from('merchants')
 64→      .select('id')
 65→      .eq('profile_id', profile!.id)
 66→      .single();
 67→
 68→    if (!merchant) return null;
 69→
 70→    const { data: campaign } = await supabase
 71→      .from('campaigns')
 72→      .insert({
 73→        merchant_id: merchant.id,
 74→        title: suggestion.title,
 75→        message: suggestion.message,
 76→        campaign_type: 'ai_suggested',
 77→        target_audience: suggestion.target_audience,
 78→        status: 'draft',
 79→        offer_type: suggestion.offer_type,
 80→        offer_value: suggestion.offer_value,
 81→        offer_description: suggestion.offer_description,
 82→      })
 83→      .select('id')
 84→      .single();
 85→
 86→    // Update local state
 87→    setSuggestions((prev) =>
 88→      prev.map((s) => (s.id === id ? { ...s, status: 'accepted' as const } : s))
 89→    );
 90→
 91→    return campaign?.id || null;
 92→  };
 93→
 94→  const rejectSuggestion = async (id: string) => {
 95→    await supabase
 96→      .from('ai_campaign_suggestions')
 97→      .update({ status: 'rejected' })
 98→      .eq('id', id);
 99→
100→    setSuggestions((prev) =>
101→      prev.map((s) => (s.id === id ? { ...s, status: 'rejected' as const } : s))
102→    );
103→  };
104→
105→  return {
106→    suggestions,
107→    pendingSuggestions,
108→    loading,
109→    error,
110→    acceptSuggestion,
111→    rejectSuggestion,
112→    refetch: fetchSuggestions,
113→  };
114→}
