  4→import type { WorkflowLog } from '@astrolab/shared';
  5→
  6→const PAGE_SIZE = 20;
  7→
  8→export function useWorkflowLogs() {
  9→  const { profile } = useAuth();
 10→  const [logs, setLogs] = useState<WorkflowLog[]>([]);
 11→  const [loading, setLoading] = useState(true);
 12→  const [filter, setFilter] = useState<string>('all');
 13→  const [page, setPage] = useState(1);
 14→  const [totalPages, setTotalPages] = useState(1);
 15→
 16→  const fetchLogs = useCallback(async () => {
 17→    if (!profile) return;
 18→
 19→    setLoading(true);
 20→
 21→    const { data: merchant } = await supabase
 22→      .from('merchants')
 23→      .select('id')
 24→      .eq('profile_id', profile.id)
 25→      .single();
 26→
 27→    if (!merchant) {
 28→      setLoading(false);
 29→      return;
 30→    }
 31→
 32→    let query = supabase
 33→      .from('workflow_logs')
 34→      .select('*', { count: 'exact' })
 35→      .eq('merchant_id', merchant.id)
 36→      .order('created_at', { ascending: false });
 37→
 38→    if (filter !== 'all') {
 39→      query = query.eq('workflow_name', filter);
 40→    }
 41→
 42→    const from = (page - 1) * PAGE_SIZE;
 43→    const to = from + PAGE_SIZE - 1;
 44→    query = query.range(from, to);
 45→
 46→    const { data, count } = await query;
 47→
 48→    setLogs((data as WorkflowLog[]) || []);
 49→    setTotalPages(Math.ceil((count || 0) / PAGE_SIZE));
 50→    setLoading(false);
 51→  }, [profile, filter, page]);
 52→
 53→  useEffect(() => {
 54→    fetchLogs();
 55→  }, [fetchLogs]);
 56→
 57→  // Automation stats
 58→  const [stats, setStats] = useState({
 59→    scheduledCampaigns: 0,
 60→    lastInactivityRun: null as string | null,
 61→    inactivityClientsTargeted: 0,
 62→    pendingSuggestions: 0,
 63→    welcomeSentThisWeek: 0,
 64→    rewardRemindersThisWeek: 0,
 65→  });
 66→
 67→  useEffect(() => {
 68→    if (!profile) return;
 69→
 70→    async function loadStats() {
 71→      const { data: merchant } = await supabase
 72→        .from('merchants')
 73→        .select('id')
 74→        .eq('profile_id', profile!.id)
 75→        .single();
 76→
 77→      if (!merchant) return;
 78→
 79→      // Scheduled campaigns count
 80→      const { count: scheduledCount } = await supabase
 81→        .from('campaigns')
 82→        .select('id', { count: 'exact', head: true })
 83→        .eq('merchant_id', merchant.id)
 84→        .eq('status', 'scheduled');
 85→
 86→      // Pending suggestions
 87→      const { count: suggestionsCount } = await supabase
 88→        .from('ai_campaign_suggestions')
 89→        .select('id', { count: 'exact', head: true })
 90→        .eq('merchant_id', merchant.id)
 91→        .eq('status', 'pending');
 92→
 93→      // Logs this week
 94→      const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
 95→
 96→      const { count: welcomeCount } = await supabase
 97→        .from('workflow_logs')
 98→        .select('id', { count: 'exact', head: true })
 99→        .eq('merchant_id', merchant.id)
100→        .eq('workflow_name', 'welcome-new-customer')
101→        .eq('status', 'success')
102→        .gte('created_at', weekAgo);
103→
104→      const { count: rewardCount } = await supabase
105→        .from('workflow_logs')
106→        .select('id', { count: 'exact', head: true })
107→        .eq('merchant_id', merchant.id)
108→        .eq('workflow_name', 'reward-reminder')
109→        .eq('status', 'success')
110→        .gte('created_at', weekAgo);
111→
112→      // Last inactivity run
113→      const { data: lastInactivity } = await supabase
114→        .from('workflow_logs')
115→        .select('created_at, output_data')
116→        .eq('merchant_id', merchant.id)
117→        .eq('workflow_name', 'inactivity-alert')
118→        .eq('status', 'success')
119→        .order('created_at', { ascending: false })
120→        .limit(1)
121→        .maybeSingle();
122→
123→      setStats({
124→        scheduledCampaigns: scheduledCount || 0,
125→        pendingSuggestions: suggestionsCount || 0,
126→        welcomeSentThisWeek: welcomeCount || 0,
127→        rewardRemindersThisWeek: rewardCount || 0,
128→        lastInactivityRun: lastInactivity?.created_at || null,
129→        inactivityClientsTargeted:
130→          (lastInactivity?.output_data as Record<string, number>)?.inactive_count || 0,
131→      });
132→    }
133→
134→    loadStats();
135→  }, [profile]);
136→
137→  return { logs, loading, filter, setFilter, page, setPage, totalPages, stats, refetch: fetchLogs };
138→}
