  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import { useToast } from '../components/ui/Toast';
  5→import type { Reward, RewardType } from '@astrolab/shared';
  6→
  7→interface CreateRewardData {
  8→  name: string;
  9→  description?: string;
 10→  reward_type: RewardType;
 11→  points_required?: number;
 12→  stamps_required?: number;
 13→}
 14→
 15→interface UseMerchantRewardsReturn {
 16→  rewards: Reward[];
 17→  loading: boolean;
 18→  error: string | null;
 19→  createReward: (data: CreateRewardData) => Promise<boolean>;
 20→  updateReward: (id: string, data: Partial<CreateRewardData>) => Promise<boolean>;
 21→  toggleReward: (id: string) => Promise<void>;
 22→  deleteReward: (id: string) => Promise<boolean>;
 23→  refetch: () => void;
 24→}
 25→
 26→export function useMerchantRewards(): UseMerchantRewardsReturn {
 27→  const { user } = useAuth();
 28→  const { toast } = useToast();
 29→  const [rewards, setRewards] = useState<Reward[]>([]);
 30→  const [loading, setLoading] = useState(true);
 31→  const [error, setError] = useState<string | null>(null);
 32→  const [merchantId, setMerchantId] = useState<string | null>(null);
 33→
 34→  const fetchRewards = useCallback(async () => {
 35→    if (!user) { setLoading(false); return; }
 36→    setLoading(true);
 37→
 38→    const { data: merchant } = await supabase
 39→      .from('merchants')
 40→      .select('id')
 41→      .eq('profile_id', user.id)
 42→      .single();
 43→
 44→    if (!merchant) { setLoading(false); return; }
 45→    setMerchantId(merchant.id);
 46→
 47→    const { data, error: fetchError } = await supabase
 48→      .from('rewards')
 49→      .select('*')
 50→      .eq('merchant_id', merchant.id)
 51→      .order('created_at', { ascending: false });
 52→
 53→    if (fetchError) {
 54→      setError('Impossible de charger les recompenses');
 55→    } else {
 56→      setRewards((data ?? []) as Reward[]);
 57→    }
 58→    setLoading(false);
 59→  }, [user]);
 60→
 61→  useEffect(() => { fetchRewards(); }, [fetchRewards]);
 62→
 63→  const createReward = useCallback(async (data: CreateRewardData): Promise<boolean> => {
 64→    if (!merchantId) return false;
 65→    const { error: insertError } = await supabase.from('rewards').insert({
 66→      merchant_id: merchantId,
 67→      name: data.name,
 68→      description: data.description || null,
 69→      reward_type: data.reward_type,
 70→      points_required: data.points_required || null,
 71→      stamps_required: data.stamps_required || null,
 72→      is_active: true,
 73→    });
 74→    if (insertError) {
 75→      toast('Erreur lors de la creation', 'error');
 76→      return false;
 77→    }
 78→    toast('Recompense creee', 'success');
 79→    fetchRewards();
 80→    return true;
 81→  }, [merchantId, fetchRewards, toast]);
 82→
 83→  const updateReward = useCallback(async (id: string, data: Partial<CreateRewardData>): Promise<boolean> => {
 84→    const { error: updateError } = await supabase
 85→      .from('rewards')
 86→      .update({
 87→        name: data.name,
 88→        description: data.description || null,
 89→        reward_type: data.reward_type,
 90→        points_required: data.points_required || null,
 91→        stamps_required: data.stamps_required || null,
 92→      })
 93→      .eq('id', id);
 94→    if (updateError) {
 95→      toast('Erreur lors de la modification', 'error');
 96→      return false;
 97→    }
 98→    toast('Recompense modifiee', 'success');
 99→    fetchRewards();
100→    return true;
101→  }, [fetchRewards, toast]);
102→
103→  const toggleReward = useCallback(async (id: string) => {
104→    const reward = rewards.find((r) => r.id === id);
105→    if (!reward) return;
106→    await supabase
107→      .from('rewards')
108→      .update({ is_active: !reward.is_active })
109→      .eq('id', id);
110→    toast(reward.is_active ? 'Recompense desactivee' : 'Recompense activee', 'success');
111→    fetchRewards();
112→  }, [rewards, fetchRewards, toast]);
113→
114→  const deleteReward = useCallback(async (id: string): Promise<boolean> => {
115→    const { error: deleteError } = await supabase
116→      .from('rewards')
117→      .delete()
118→      .eq('id', id);
119→    if (deleteError) {
120→      toast('Impossible de supprimer cette recompense', 'error');
121→      return false;
122→    }
123→    toast('Recompense supprimee', 'success');
124→    fetchRewards();
125→    return true;
126→  }, [fetchRewards, toast]);
127→
128→  return { rewards, loading, error, createReward, updateReward, toggleReward, deleteReward, refetch: fetchRewards };
129→}
