  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { Scan } from '@astrolab/shared';
  5→
  6→export interface ScanWithMerchant extends Scan {
  7→  merchant_name: string;
  8→}
  9→
 10→interface UseScanHistoryReturn {
 11→  scans: ScanWithMerchant[];
 12→  totalCount: number;
 13→  page: number;
 14→  loading: boolean;
 15→  error: string | null;
 16→  nextPage: () => void;
 17→  prevPage: () => void;
 18→  setPage: (p: number) => void;
 19→}
 20→
 21→export function useScanHistory(
 22→  pageSize = 20,
 23→  merchantId?: string
 24→): UseScanHistoryReturn {
 25→  const { user } = useAuth();
 26→  const [scans, setScans] = useState<ScanWithMerchant[]>([]);
 27→  const [totalCount, setTotalCount] = useState(0);
 28→  const [page, setPage] = useState(1);
 29→  const [loading, setLoading] = useState(true);
 30→  const [error, setError] = useState<string | null>(null);
 31→
 32→  const fetchScans = useCallback(async () => {
 33→    if (!user) {
 34→      setLoading(false);
 35→      return;
 36→    }
 37→
 38→    setLoading(true);
 39→    setError(null);
 40→
 41→    const { data: customer } = await supabase
 42→      .from('customers')
 43→      .select('id')
 44→      .eq('profile_id', user.id)
 45→      .single();
 46→
 47→    if (!customer) {
 48→      setScans([]);
 49→      setLoading(false);
 50→      return;
 51→    }
 52→
 53→    let query = supabase
 54→      .from('scans')
 55→      .select(
 56→        '*, merchants!scans_merchant_id_fkey(business_name)',
 57→        { count: 'exact' }
 58→      )
 59→      .eq('customer_id', customer.id)
 60→      .order('scanned_at', { ascending: false });
 61→
 62→    if (merchantId) {
 63→      query = query.eq('merchant_id', merchantId);
 64→    }
 65→
 66→    const from = (page - 1) * pageSize;
 67→    const to = from + pageSize - 1;
 68→    query = query.range(from, to);
 69→
 70→    const { data, count, error: fetchError } = await query;
 71→
 72→    if (fetchError) {
 73→      setError('Impossible de charger l\'historique');
 74→      setLoading(false);
 75→      return;
 76→    }
 77→
 78→    const mapped = (data ?? []).map((row) => {
 79→      const merchant = (row as Record<string, unknown>).merchants as {
 80→        business_name: string;
 81→      } | null;
 82→      return {
 83→        ...row,
 84→        merchant_name: merchant?.business_name ?? 'Commerce',
 85→      } as unknown as ScanWithMerchant;
 86→    });
 87→
 88→    setScans(mapped);
 89→    setTotalCount(count ?? 0);
 90→    setLoading(false);
 91→  }, [user, page, pageSize, merchantId]);
 92→
 93→  useEffect(() => {
 94→    fetchScans();
 95→  }, [fetchScans]);
 96→
 97→  const nextPage = useCallback(() => {
 98→    const maxPage = Math.ceil(totalCount / pageSize);
 99→    setPage((p) => Math.min(p + 1, maxPage));
100→  }, [totalCount, pageSize]);
101→
102→  const prevPage = useCallback(() => {
103→    setPage((p) => Math.max(p - 1, 1));
104→  }, []);
105→
106→  return { scans, totalCount, page, loading, error, nextPage, prevPage, setPage };
107→}
