 1→import { useState, useEffect } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import { useAuth } from './useAuth';
 4→import type { PlanLimits, SubscriptionPlan } from '@astrolab/shared';
 5→
 6→const PLAN_MAX_CLIENTS: Record<SubscriptionPlan, number | null> = {
 7→  starter: 500,
 8→  pro: null,
 9→  business: null,
10→};
11→
12→export function usePlanLimits() {
13→  const { profile } = useAuth();
14→  const [limits, setLimits] = useState<PlanLimits>({
15→    plan: 'starter',
16→    canScheduleCampaigns: false,
17→    canUseAICampaigns: false,
18→    maxClients: 500,
19→    currentClientCount: 0,
20→    isAtClientLimit: false,
21→    canCreateCampaign: true,
22→  });
23→  const [loading, setLoading] = useState(true);
24→
25→  useEffect(() => {
26→    if (!profile) return;
27→
28→    async function fetchLimits() {
29→      setLoading(true);
30→
31→      const { data: merchant } = await supabase
32→        .from('merchants')
33→        .select('id, subscription_plan, subscription_status')
34→        .eq('profile_id', profile!.id)
35→        .single();
36→
37→      if (!merchant) {
38→        setLoading(false);
39→        return;
40→      }
41→
42→      const status = merchant.subscription_status;
43→      const plan = (merchant.subscription_plan || 'starter') as SubscriptionPlan;
44→
45→      // Trial users get Pro-level access
46→      const effectivePlan: SubscriptionPlan =
47→        status === 'trial' ? 'pro' : plan;
48→      const maxClients = PLAN_MAX_CLIENTS[effectivePlan];
49→
50→      // Count current clients
51→      const { count } = await supabase
52→        .from('loyalty_cards')
53→        .select('id', { count: 'exact', head: true })
54→        .eq('merchant_id', merchant.id);
55→
56→      const currentClientCount = count ?? 0;
57→
58→      const canCreate =
59→        status !== 'cancelled' && status !== 'past_due';
60→
61→      setLimits({
62→        plan: effectivePlan,
63→        canScheduleCampaigns: effectivePlan !== 'starter',
64→        canUseAICampaigns: effectivePlan !== 'starter',
65→        maxClients,
66→        currentClientCount,
67→        isAtClientLimit: maxClients !== null && currentClientCount >= maxClients,
68→        canCreateCampaign: canCreate,
69→      });
70→
71→      setLoading(false);
72→    }
73→
74→    fetchLimits();
75→  }, [profile]);
76→
77→  return { limits, loading };
78→}
