 1→import { useState, useEffect } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import type { Reward } from '@astrolab/shared';
 4→
 5→export interface RewardWithProgress extends Reward {
 6→  is_available: boolean;
 7→  progress_percent: number;
 8→  points_remaining?: number;
 9→  stamps_remaining?: number;
10→}
11→
12→interface UseRewardsReturn {
13→  rewards: RewardWithProgress[];
14→  loading: boolean;
15→  error: string | null;
16→}
17→
18→export function useRewards(
19→  merchantId: string | undefined,
20→  currentPoints: number,
21→  currentStamps: number
22→): UseRewardsReturn {
23→  const [rewards, setRewards] = useState<RewardWithProgress[]>([]);
24→  const [loading, setLoading] = useState(true);
25→  const [error, setError] = useState<string | null>(null);
26→
27→  useEffect(() => {
28→    if (!merchantId) {
29→      setLoading(false);
30→      return;
31→    }
32→
33→    async function fetchRewards() {
34→      setLoading(true);
35→
36→      const { data, error: fetchError } = await supabase
37→        .from('rewards')
38→        .select('*')
39→        .eq('merchant_id', merchantId!)
40→        .eq('is_active', true)
41→        .order('points_required', { ascending: true });
42→
43→      if (fetchError) {
44→        setError('Impossible de charger les recompenses');
45→        setLoading(false);
46→        return;
47→      }
48→
49→      const mapped: RewardWithProgress[] = (data ?? []).map((reward) => {
50→        const r = reward as Reward;
51→        let is_available = false;
52→        let progress_percent = 0;
53→        let points_remaining: number | undefined;
54→        let stamps_remaining: number | undefined;
55→
56→        if (r.reward_type === 'points' && r.points_required) {
57→          is_available = currentPoints >= r.points_required;
58→          progress_percent = Math.min(
59→            100,
60→            Math.round((currentPoints / r.points_required) * 100)
61→          );
62→          points_remaining = is_available
63→            ? 0
64→            : r.points_required - currentPoints;
65→        } else if (r.reward_type === 'stamps' && r.stamps_required) {
66→          is_available = currentStamps >= r.stamps_required;
67→          progress_percent = Math.min(
68→            100,
69→            Math.round((currentStamps / r.stamps_required) * 100)
70→          );
71→          stamps_remaining = is_available
72→            ? 0
73→            : r.stamps_required - currentStamps;
74→        }
75→
76→        return {
77→          ...r,
78→          is_available,
79→          progress_percent,
80→          points_remaining,
81→          stamps_remaining,
82→        };
83→      });
84→
85→      setRewards(mapped);
86→      setLoading(false);
87→    }
88→
89→    fetchRewards();
90→  }, [merchantId, currentPoints, currentStamps]);
91→
92→  return { rewards, loading, error };
93→}
