 87→
 88→    const { data: urlData } = supabase.storage
 89→      .from('merchant-logos')
 90→      .getPublicUrl(path);
 91→
 92→    const url = urlData.publicUrl;
 93→
 94→    await supabase
 95→      .from('merchants')
 96→      .update({ business_logo_url: url })
 97→      .eq('id', merchant.id);
 98→
 99→    toast('Logo mis a jour', 'success');
100→    fetchMerchant();
101→    return url;
102→  }, [user, merchant, fetchMerchant, toast]);
103→
104→  const updatePassword = useCallback(async (newPassword: string): Promise<boolean> => {
