  1→import { useState, useEffect, useCallback } from 'react';
  2→import { supabase } from '../lib/supabase';
  3→import { useAuth } from './useAuth';
  4→import type { MerchantClientRow } from '@astrolab/shared';
  5→
  6→interface UseMerchantClientsReturn {
  7→  clients: MerchantClientRow[];
  8→  totalCount: number;
  9→  loading: boolean;
 10→  error: string | null;
 11→  search: string;
 12→  setSearch: (s: string) => void;
 13→  page: number;
 14→  setPage: (p: number) => void;
 15→  nextPage: () => void;
 16→  prevPage: () => void;
 17→}
 18→
 19→export function useMerchantClients(pageSize = 20): UseMerchantClientsReturn {
 20→  const { user } = useAuth();
 21→  const [clients, setClients] = useState<MerchantClientRow[]>([]);
 22→  const [totalCount, setTotalCount] = useState(0);
 23→  const [loading, setLoading] = useState(true);
 24→  const [error, setError] = useState<string | null>(null);
 25→  const [search, setSearch] = useState('');
 26→  const [page, setPage] = useState(1);
 27→
 28→  const fetchClients = useCallback(async () => {
 29→    if (!user) { setLoading(false); return; }
 30→    setLoading(true);
 31→    setError(null);
 32→
 33→    const { data: merchant } = await supabase
 34→      .from('merchants')
 35→      .select('id')
 36→      .eq('profile_id', user.id)
 37→      .single();
 38→
 39→    if (!merchant) { setLoading(false); return; }
 40→
 41→    // Get loyalty cards with customer profile info
 42→    const { data: cards, error: fetchError } = await supabase
 43→      .from('loyalty_cards')
 44→      .select(
 45→        '*, customers!loyalty_cards_customer_id_fkey(id, profile_id, profiles!customers_profile_id_fkey(full_name, email))'
 46→      )
 47→      .eq('merchant_id', merchant.id)
 48→      .order('updated_at', { ascending: false });
 49→
 50→    if (fetchError) {
 51→      setError('Impossible de charger les clients');
 52→      setLoading(false);
 53→      return;
 54→    }
 55→
 56→    // Get scan counts per customer
 57→    const { data: scans } = await supabase
 58→      .from('scans')
 59→      .select('customer_id, scanned_at')
 60→      .eq('merchant_id', merchant.id);
 61→
 62→    const scanMap = new Map<string, { count: number; lastScan: string | null }>();
 63→    (scans ?? []).forEach((s) => {
 64→      const existing = scanMap.get(s.customer_id);
 65→      if (!existing) {
 66→        scanMap.set(s.customer_id, { count: 1, lastScan: s.scanned_at });
 67→      } else {
 68→        existing.count++;
 69→        if (!existing.lastScan || s.scanned_at > existing.lastScan) {
 70→          existing.lastScan = s.scanned_at;
 71→        }
 72→      }
 73→    });
 74→
 75→    const mapped: MerchantClientRow[] = (cards ?? []).map((card) => {
 76→      const customer = (card as Record<string, unknown>).customers as {
 77→        id: string;
 78→        profile_id: string;
 79→        profiles: { full_name: string | null; email: string } | null;
 80→      } | null;
 81→      const profile = customer?.profiles;
 82→      const scanInfo = scanMap.get(customer?.id ?? '');
 83→
 84→      return {
 85→        customer_id: customer?.id ?? '',
 86→        profile_id: customer?.profile_id ?? '',
 87→        full_name: profile?.full_name ?? 'Client',
 88→        email: profile?.email ?? '',
 89→        total_points: card.total_points,
 90→        total_stamps: card.total_stamps,
 91→        stamps_current_card: card.stamps_current_card,
 92→        cards_completed: card.cards_completed,
 93→        last_scan_at: scanInfo?.lastScan ?? null,
 94→        visit_count: scanInfo?.count ?? 0,
 95→        loyalty_card_id: card.id,
 96→      };
 97→    });
 98→
 99→    // Search filter
100→    let filtered = mapped;
101→    if (search.trim()) {
102→      const q = search.toLowerCase();
103→      filtered = mapped.filter(
104→        (c) =>
105→          c.full_name.toLowerCase().includes(q) ||
106→          c.email.toLowerCase().includes(q)
107→      );
108→    }
109→
110→    // Sort by last scan desc
111→    filtered.sort((a, b) => {
112→      if (!a.last_scan_at && !b.last_scan_at) return 0;
113→      if (!a.last_scan_at) return 1;
114→      if (!b.last_scan_at) return -1;
115→      return new Date(b.last_scan_at).getTime() - new Date(a.last_scan_at).getTime();
116→    });
117→
118→    setTotalCount(filtered.length);
119→
120→    // Paginate
121→    const from = (page - 1) * pageSize;
122→    setClients(filtered.slice(from, from + pageSize));
123→    setLoading(false);
124→  }, [user, search, page, pageSize]);
125→
126→  useEffect(() => {
127→    fetchClients();
128→  }, [fetchClients]);
129→
130→  // Reset page on search change
131→  useEffect(() => {
132→    setPage(1);
133→  }, [search]);
134→
135→  const nextPage = useCallback(() => {
136→    const maxPage = Math.ceil(totalCount / pageSize);
137→    setPage((p) => Math.min(p + 1, maxPage));
138→  }, [totalCount, pageSize]);
139→
140→  const prevPage = useCallback(() => {
141→    setPage((p) => Math.max(p - 1, 1));
142→  }, []);
143→
144→  return { clients, totalCount, loading, error, search, setSearch, page, setPage, nextPage, prevPage };
145→}
