  1→import { useState, useEffect } from 'react';
  2→import { Link } from 'react-router-dom';
  3→import type { Merchant } from '@astrolab/shared';
  4→
  5→interface TrialBannerProps {
  6→  merchant: Merchant;
  7→}
  8→
  9→const DISMISS_KEY = 'astrolab_trial_banner_dismissed';
 10→
 11→export function TrialBanner({ merchant }: TrialBannerProps) {
 12→  const [dismissed, setDismissed] = useState(false);
 13→
 14→  useEffect(() => {
 15→    const dismissedAt = localStorage.getItem(DISMISS_KEY);
 16→    if (dismissedAt) {
 17→      const elapsed = Date.now() - parseInt(dismissedAt, 10);
 18→      if (elapsed < 24 * 60 * 60 * 1000) {
 19→        setDismissed(true);
 20→      }
 21→    }
 22→  }, []);
 23→
 24→  const status = merchant.subscription_status;
 25→
 26→  // Determine banner type
 27→  if (status === 'active') return null;
 28→
 29→  // Past due — always show, no dismiss
 30→  if (status === 'past_due') {
 31→    return (
 32→      <div className="relative rounded-lg bg-orange-100 px-4 py-3 text-sm text-orange-800">
 33→        <div className="flex items-center justify-between gap-4">
 34→          <p>
 35→            <span className="font-semibold">Paiement echoue.</span> Mettez a
 36→            jour votre moyen de paiement pour conserver votre abonnement.
 37→          </p>
 38→          <Link
 39→            to="/merchant/billing"
 40→            className="rounded-lg bg-orange-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-orange-700"
 41→          >
 42→            Mettre a jour
 43→          </Link>
 44→        </div>
 45→      </div>
 46→    );
 47→  }
 48→
 49→  // Cancelled — always show, no dismiss
 50→  if (status === 'cancelled') {
 51→    return (
 52→      <div className="relative rounded-lg bg-red-100 px-4 py-3 text-sm text-red-800">
 53→        <div className="flex items-center justify-between gap-4">
 54→          <p>
 55→            <span className="font-semibold">Abonnement annule.</span> Vous
 56→            conservez l'acces en lecture seule pendant 30 jours.
 57→            Reabonnez-vous pour retrouver toutes les fonctionnalites.
 58→          </p>
 59→          <Link
 60→            to="/merchant/billing"
 61→            className="rounded-lg bg-red-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-red-700"
 62→          >
 63→            Se reabonner
 64→          </Link>
 65→        </div>
 66→      </div>
 67→    );
 68→  }
 69→
 70→  // Trial — dismissable (except when expired)
 71→  if (status !== 'trial' || dismissed) return null;
 72→
 73→  const trialEnd = merchant.trial_ends_at
 74→    ? new Date(merchant.trial_ends_at)
 75→    : null;
 76→  const now = new Date();
 77→  const daysLeft = trialEnd
 78→    ? Math.max(
 79→        0,
 80→        Math.ceil(
 81→          (trialEnd.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)
 82→        )
 83→      )
 84→    : 0;
 85→  const isExpired = trialEnd ? trialEnd < now : false;
 86→  const isUrgent = daysLeft <= 3 && !isExpired;
 87→
 88→  function handleDismiss() {
 89→    localStorage.setItem(DISMISS_KEY, Date.now().toString());
 90→    setDismissed(true);
 91→  }
 92→
 93→  return (
 94→    <div
 95→      className={`relative rounded-lg px-4 py-3 text-sm ${
 96→        isExpired
 97→          ? 'bg-red-100 text-red-800'
 98→          : isUrgent
 99→            ? 'bg-orange-100 text-orange-800'
100→            : 'bg-amber-100 text-amber-800'
101→      }`}
102→    >
103→      <div className="flex items-center justify-between gap-4">
104→        <p>
105→          {isExpired
106→            ? 'Votre essai gratuit a expire. Passez a un plan payant pour continuer.'
107→            : isUrgent
108→              ? `Plus que ${daysLeft} jour${daysLeft > 1 ? 's' : ''} d'essai ! Choisissez votre plan pour ne pas perdre l'acces.`
109→              : `Il vous reste ${daysLeft} jour${daysLeft > 1 ? 's' : ''} d'essai gratuit.`}
110→        </p>
111→        <div className="flex items-center gap-2">
112→          <Link
113→            to="/merchant/billing"
114→            className={`rounded-lg px-3 py-1.5 text-xs font-medium text-white ${
115→              isExpired
116→                ? 'bg-red-600 hover:bg-red-700'
117→                : isUrgent
118→                  ? 'bg-orange-600 hover:bg-orange-700'
119→                  : 'bg-amber-600 hover:bg-amber-700'
120→            }`}
121→          >
122→            Voir les plans
123→          </Link>
124→          {!isExpired && (
125→            <button
126→              onClick={handleDismiss}
127→              className={
128→                isUrgent
129→                  ? 'text-orange-600 hover:text-orange-800'
130→                  : 'text-amber-600 hover:text-amber-800'
131→              }
132→            >
133→              &#10005;
134→            </button>
135→          )}
136→        </div>
137→      </div>
138→    </div>
139→  );
140→}
