10→export function QRScanner({ onScan, onError }: QRScannerProps) {
11→  const [isScanning, setIsScanning] = useState(false);
12→  const [permissionDenied, setPermissionDenied] = useState(false);
13→  const scannerRef = useRef<Html5Qrcode | null>(null);
14→  const regionId = 'qr-reader';
15→
16→  async function startScanning() {
17→    try {
18→      const scanner = new Html5Qrcode(regionId);
19→      scannerRef.current = scanner;
20→
21→      await scanner.start(
22→        { facingMode: 'environment' },
23→        { fps: 10, qrbox: { width: 250, height: 250 } },
24→        (decodedText) => {
25→          onScan(decodedText);
26→          stopScanning();
27→        },
28→        () => {
29→          // Scan en cours, pas de QR detecte — silencieux
30→        }
31→      );
32→
33→      setIsScanning(true);
34→      setPermissionDenied(false);
35→    } catch (err) {
36→      const message = err instanceof Error ? err.message : String(err);
37→      if (message.includes('Permission') || message.includes('NotAllowed')) {
38→        setPermissionDenied(true);
39→      }
40→      onError?.(message);
41→    }
42→  }
43→
44→  async function stopScanning() {
45→    if (scannerRef.current?.isScanning) {
46→      await scannerRef.current.stop();
47→    }
48→    setIsScanning(false);
49→  }
50→
51→  useEffect(() => {
52→    return () => {
53→      if (scannerRef.current?.isScanning) {
54→        scannerRef.current.stop().catch(() => {});
55→      }
56→    };
57→  }, []);
58→
59→  return (
60→    <div className="space-y-4">
61→      <div
62→        id={regionId}
63→        className="mx-auto overflow-hidden rounded-lg"
64→        style={{ maxWidth: 400 }}
65→      />
66→
67→      {permissionDenied && (
68→        <p className="text-center text-sm text-red-600">
69→          Acces a la camera refuse. Veuillez autoriser l'acces dans les
70→          parametres de votre navigateur.
71→        </p>
72→      )}
73→
74→      <div className="flex justify-center">
75→        {isScanning ? (
76→          <Button variant="danger" onClick={stopScanning}>
77→            Arreter le scanner
78→          </Button>
79→        ) : (
80→          <Button onClick={startScanning}>Activer la camera</Button>
81→        )}
82→      </div>
83→    </div>
84→  );
85→}
