  1→import { useState, useEffect } from 'react';
  2→import { AppLayout } from '../../components/layout/AppLayout';
  3→import { Card } from '../../components/ui/Card';
  4→import { Tabs } from '../../components/ui/Tabs';
  5→import { Pagination } from '../../components/ui/Pagination';
  6→import { SkeletonList } from '../../components/ui/Skeleton';
  7→import { EmptyState } from '../../components/ui/EmptyState';
  8→import { useScanHistory } from '../../hooks/useScanHistory';
  9→import { useCustomerOffers } from '../../hooks/useCustomerOffers';
 10→
 11→const typeTabs = [
 12→  { label: 'Tous', value: 'all' },
 13→  { label: 'Scans', value: 'scans' },
 14→  { label: 'Offres', value: 'offers' },
 15→];
 16→
 17→const periodTabs = [
 18→  { label: 'Tout', value: 'all' },
 19→  { label: 'Cette semaine', value: 'week' },
 20→  { label: 'Ce mois', value: 'month' },
 21→];
 22→
 23→interface TimelineItem {
 24→  id: string;
 25→  type: 'scan' | 'redemption';
 26→  date: string;
 27→  label: string;
 28→  detail: string;
 29→  icon: string;
 30→}
 31→
 32→export function CustomerHistory() {
 33→  const [typeFilter, setTypeFilter] = useState('all');
 34→  const [periodFilter, setPeriodFilter] = useState('all');
 35→  const [page, setPage] = useState(1);
 36→
 37→  const {
 38→    scans,
 39→    totalCount,
 40→    loading: scansLoading,
 41→    setPage: setScanPage,
 42→  } = useScanHistory(20);
 43→
 44→  const { offers, loading: offersLoading } = useCustomerOffers();
 45→
 46→  // Reset page quand on change de filtre
 47→  useEffect(() => {
 48→    setPage(1);
 49→    setScanPage(1);
 50→  }, [typeFilter, periodFilter, setScanPage]);
 51→
 52→  const loading = scansLoading || offersLoading;
 53→
 54→  // Construire la timeline
 55→  const scanItems: TimelineItem[] = scans.map((s) => ({
 56→    id: `scan-${s.id}`,
 57→    type: 'scan',
 58→    date: s.scanned_at,
 59→    label:
 60→      s.points_earned > 0
 61→        ? `+${s.points_earned} points chez ${s.merchant_name}`
 62→        : `+${s.stamps_earned} tampon${s.stamps_earned > 1 ? 's' : ''} chez ${s.merchant_name}`,
 63→    detail: new Date(s.scanned_at).toLocaleDateString('fr-FR', {
 64→      day: 'numeric',
 65→      month: 'long',
 66→      year: 'numeric',
 67→      hour: '2-digit',
 68→      minute: '2-digit',
 69→    }),
 70→    icon: '📱',
 71→  }));
 72→
 73→  const redemptionItems: TimelineItem[] = offers
 74→    .filter((o) => o.status === 'redeemed' && o.redeemed_at)
 75→    .map((o) => ({
 76→      id: `redeem-${o.qr_code.id}`,
 77→      type: 'redemption',
 78→      date: o.redeemed_at!,
 79→      label: `Offre "${o.campaign.title}" utilisee`,
 80→      detail: new Date(o.redeemed_at!).toLocaleDateString('fr-FR', {
 81→        day: 'numeric',
 82→        month: 'long',
 83→        year: 'numeric',
 84→        hour: '2-digit',
 85→        minute: '2-digit',
 86→      }),
 87→      icon: '🎁',
 88→    }));
 89→
 90→  let items: TimelineItem[] = [];
 91→  if (typeFilter === 'all') items = [...scanItems, ...redemptionItems];
 92→  else if (typeFilter === 'scans') items = scanItems;
 93→  else items = redemptionItems;
 94→
 95→  // Filtre par periode
 96→  const now = new Date();
 97→  if (periodFilter === 'week') {
 98→    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
 99→    items = items.filter((i) => new Date(i.date) >= weekAgo);
100→  } else if (periodFilter === 'month') {
101→    const monthAgo = new Date(now.getFullYear(), now.getMonth(), 1);
102→    items = items.filter((i) => new Date(i.date) >= monthAgo);
103→  }
104→
105→  // Tri par date descendante
106→  items.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
107→
108→  // Pagination locale pour la vue combinee
109→  const pageSize = 20;
110→  const totalItems = typeFilter === 'scans' ? totalCount : items.length;
111→  const totalPages = Math.ceil(totalItems / pageSize);
112→  const pagedItems =
113→    typeFilter === 'scans'
114→      ? items
115→      : items.slice((page - 1) * pageSize, page * pageSize);
116→
117→  return (
118→    <AppLayout>
119→      <div className="space-y-6">
120→        <h1 className="text-2xl font-bold text-[var(--color-text)]">
121→          Historique
122→        </h1>
123→
124→        <div className="space-y-3">
125→          <Tabs tabs={typeTabs} activeTab={typeFilter} onTabChange={setTypeFilter} />
126→          <Tabs
127→            tabs={periodTabs}
128→            activeTab={periodFilter}
129→            onTabChange={setPeriodFilter}
130→          />
131→        </div>
132→
133→        {loading ? (
134→          <Card>
135→            <SkeletonList rows={10} />
136→          </Card>
137→        ) : pagedItems.length === 0 ? (
138→          <EmptyState
139→            icon="📊"
140→            title="Aucune activite"
141→            description="Votre historique d'activite apparaitra ici."
142→          />
143→        ) : (
144→          <>
145→            <Card>
146→              <div className="divide-y">
147→                {pagedItems.map((item) => (
148→                  <div
149→                    key={item.id}
150→                    className="flex items-center gap-3 py-3 first:pt-0 last:pb-0"
151→                  >
152→                    <span className="text-xl">{item.icon}</span>
153→                    <div className="flex-1">
