156→                      </p>
157→                      <p className="text-xs text-[var(--color-text-muted)]">
158→                        {item.detail}
159→                      </p>
160→                    </div>
161→                  </div>
162→                ))}
163→              </div>
164→            </Card>
165→            {totalPages > 1 && (
