  9→/**
 10→ * Campaign redirect page: /campaign/:campaignId
 11→ * Identifies the connected customer, finds their unique QR token,
 12→ * and redirects to /offer/{token}.
 13→ */
 14→export function CampaignRedirect() {
 15→  const { campaignId } = useParams<{ campaignId: string }>();
 16→  const { isAuthenticated, loading: authLoading, profile } = useAuth();
 17→  const navigate = useNavigate();
 18→
 19→  const [error, setError] = useState<string | null>(null);
 20→  const [loading, setLoading] = useState(true);
 21→
 22→  useEffect(() => {
 23→    if (authLoading) return;
 24→
 25→    if (!isAuthenticated) {
 26→      navigate(`/login?redirect=/campaign/${campaignId}`, { replace: true });
 27→      return;
 28→    }
 29→
 30→    if (!campaignId || !profile) return;
 31→
 32→    async function findQRCode() {
 33→      setLoading(true);
 34→      setError(null);
 35→
 36→      try {
 37→        // Get customer_id from profile
 38→        const { data: customer } = await supabase
 39→          .from('customers')
 40→          .select('id')
 41→          .eq('profile_id', profile!.id)
 42→          .single();
 43→
 44→        if (!customer) {
 45→          setError('Profil client introuvable.');
 46→          setLoading(false);
 47→          return;
 48→        }
 49→
 50→        // Find the campaign QR code for this customer
 51→        const { data: qrCode } = await supabase
 52→          .from('qr_codes')
 53→          .select('token, is_active, expires_at')
 54→          .eq('campaign_id', campaignId)
 55→          .eq('customer_id', customer.id)
 56→          .eq('qr_type', 'campaign')
 57→          .single();
 58→
 59→        if (!qrCode) {
 60→          setError('Cette offre ne vous est pas destinee.');
 61→          setLoading(false);
 62→          return;
 63→        }
 64→
 65→        if (!qrCode.is_active) {
 66→          setError('Cette offre a deja ete utilisee.');
 67→          setLoading(false);
 68→          return;
 69→        }
 70→
 71→        if (qrCode.expires_at && new Date(qrCode.expires_at) < new Date()) {
 72→          setError('Cette offre a expire.');
 73→          setLoading(false);
 74→          return;
 75→        }
 76→
 77→        // Redirect to offer page
 78→        navigate(`/offer/${qrCode.token}`, { replace: true });
 79→      } catch {
 80→        setError('Une erreur est survenue.');
 81→        setLoading(false);
 82→      }
 83→    }
 84→
 85→    findQRCode();
 86→  }, [campaignId, isAuthenticated, authLoading, profile, navigate]);
 87→
 88→  if (authLoading || loading) {
 89→    return (
 90→      <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg)]">
 91→        <div className="text-center">
 92→          <Spinner size="lg" />
 93→          <p className="mt-4 text-[var(--color-text-muted)]">
 94→            Chargement de l'offre...
 95→          </p>
 96→        </div>
 97→      </div>
 98→    );
 99→  }
100→
101→  if (error) {
102→    return (
103→      <div className="flex min-h-screen items-center justify-center bg-[var(--color-bg)] px-4">
104→        <Card className="max-w-md text-center">
105→          <div className="mb-4 text-5xl">&#128533;</div>
106→          <h2 className="mb-2 text-xl font-bold text-[var(--color-text)]">
107→            Offre indisponible
108→          </h2>
109→          <p className="mb-6 text-[var(--color-text-muted)]">{error}</p>
110→          <Button onClick={() => navigate('/customer/dashboard')}>
111→            Retour a l'accueil
112→          </Button>
113→        </Card>
114→      </div>
115→    );
116→  }
117→
118→  return null;
119→}
