 42→      const campaign = (qrCode as Record<string, unknown>).campaigns as
 43→        | { title: string; offer_description: string | null }
 44→        | null;
 45→
 46→      // Verifier si deja utilise
 47→      let alreadyRedeemed = false;
 48→      if (qrCode.customer_id && qrCode.campaign_id) {
 49→        const { data: redemption } = await supabase
 50→          .from('campaign_redemptions')
 51→          .select('id')
 52→          .eq('campaign_id', qrCode.campaign_id)
 53→          .eq('customer_id', qrCode.customer_id)
 54→          .maybeSingle();
