 1→import { useEffect, useRef } from 'react';
 2→import * as Brightness from 'expo-brightness';
 3→
 4→export function useBrightness(shouldMaximize: boolean) {
 5→  const previousBrightness = useRef<number | null>(null);
 6→
 7→  useEffect(() => {
 8→    if (!shouldMaximize) return;
 9→
10→    let mounted = true;
11→
12→    const maximize = async () => {
13→      try {
14→        const current = await Brightness.getBrightnessAsync();
15→        if (mounted) {
16→          previousBrightness.current = current;
17→          await Brightness.setBrightnessAsync(1);
18→        }
19→      } catch {
20→        // Permission denied or not available
21→      }
22→    };
23→
24→    maximize();
25→
26→    return () => {
27→      mounted = false;
28→      if (previousBrightness.current !== null) {
29→        Brightness.setBrightnessAsync(previousBrightness.current).catch(() => {});
30→      }
31→    };
32→  }, [shouldMaximize]);
33→}
