 1→import { useState, useEffect, useCallback } from 'react';
 2→import { getCached, setCache } from '../lib/cache';
 3→
 4→interface UseCachedQueryResult<T> {
 5→  data: T | null;
 6→  loading: boolean;
 7→  error: string | null;
 8→  isFromCache: boolean;
 9→  refresh: () => Promise<void>;
10→}
11→
12→export function useCachedQuery<T>(
13→  cacheKey: string,
14→  fetcher: () => Promise<T>,
15→  deps: unknown[] = []
16→): UseCachedQueryResult<T> {
17→  const [data, setData] = useState<T | null>(null);
18→  const [loading, setLoading] = useState(true);
19→  const [error, setError] = useState<string | null>(null);
20→  const [isFromCache, setIsFromCache] = useState(false);
21→
22→  const fetchData = useCallback(async () => {
23→    setLoading(true);
24→    setError(null);
25→
26→    // Try cache first
27→    const cached = await getCached<T>(cacheKey);
28→    if (cached) {
29→      setData(cached);
30→      setIsFromCache(true);
31→      setLoading(false);
32→    }
33→
34→    // Then fetch fresh data
35→    try {
36→      const fresh = await fetcher();
37→      setData(fresh);
38→      setIsFromCache(false);
39→      await setCache(cacheKey, fresh);
40→    } catch (err) {
41→      if (!cached) {
42→        setError(err instanceof Error ? err.message : 'Erreur inconnue');
43→      }
44→      // If we have cache, keep showing it
45→    } finally {
46→      setLoading(false);
47→    }
48→  }, [cacheKey, ...deps]);
49→
50→  useEffect(() => {
51→    fetchData();
52→  }, [fetchData]);
53→
54→  return { data, loading, error, isFromCache, refresh: fetchData };
55→}
