 1→import React, { useEffect } from 'react';
 2→import { View, Text, StyleSheet } from 'react-native';
 3→import Svg, { Circle } from 'react-native-svg';
 4→import Animated, {
 5→  useSharedValue,
 6→  useAnimatedProps,
 7→  withTiming,
 8→} from 'react-native-reanimated';
 9→import { theme } from '../../theme';
10→
11→const AnimatedCircle = Animated.createAnimatedComponent(Circle);
12→
13→interface CircularProgressProps {
14→  progress: number; // 0 to 1
15→  size?: number;
16→  strokeWidth?: number;
17→  color?: string;
18→  label?: string;
19→}
20→
21→export function CircularProgress({
22→  progress,
23→  size = 120,
24→  strokeWidth = 10,
25→  color = theme.colors.primary,
26→  label,
27→}: CircularProgressProps) {
28→  const radius = (size - strokeWidth) / 2;
29→  const circumference = 2 * Math.PI * radius;
30→  const animatedProgress = useSharedValue(0);
31→
32→  useEffect(() => {
33→    animatedProgress.value = withTiming(progress, { duration: 1000 });
34→  }, [progress]);
35→
36→  const animatedProps = useAnimatedProps(() => ({
37→    strokeDashoffset: circumference * (1 - animatedProgress.value),
38→  }));
39→
40→  return (
41→    <View style={[styles.container, { width: size, height: size }]}>
42→      <Svg width={size} height={size}>
43→        <Circle
44→          cx={size / 2}
45→          cy={size / 2}
46→          r={radius}
47→          stroke={theme.colors.border}
48→          strokeWidth={strokeWidth}
49→          fill="none"
50→        />
51→        <AnimatedCircle
52→          cx={size / 2}
53→          cy={size / 2}
54→          r={radius}
55→          stroke={color}
56→          strokeWidth={strokeWidth}
57→          fill="none"
58→          strokeDasharray={circumference}
59→          animatedProps={animatedProps}
60→          strokeLinecap="round"
61→          rotation="-90"
62→          origin={`${size / 2}, ${size / 2}`}
63→        />
64→      </Svg>
65→      {label && (
66→        <View style={styles.labelContainer}>
67→          <Text style={styles.label}>{label}</Text>
68→        </View>
69→      )}
70→    </View>
71→  );
72→}
