 13→
 14→const { height: SCREEN_HEIGHT } = Dimensions.get('window');
 15→
 16→interface ScanResultProps {
 17→  success: boolean;
 18→  data?: CustomerScanSuccessData;
 19→  error?: { code: string; message: string };
 20→  onViewCard?: () => void;
 21→  onScanAgain: () => void;
 22→  onDismiss?: () => void;
 23→}
 24→
 25→export function ScanResult({
 26→  success,
 27→  data,
 28→  error,
 29→  onViewCard,
 30→  onScanAgain,
 31→  onDismiss,
 32→}: ScanResultProps) {
 33→  const translateY = useSharedValue(SCREEN_HEIGHT);
 34→
 35→  useEffect(() => {
 36→    translateY.value = withSpring(0, { damping: 20, stiffness: 150 });
 37→
 38→    // Auto-dismiss after 10 seconds
 39→    const timer = setTimeout(() => {
 40→      if (onDismiss) {
 41→        translateY.value = withTiming(SCREEN_HEIGHT, { duration: 300 }, () => {
 42→          runOnJS(onDismiss)();
 43→        });
 44→      }
 45→    }, 10000);
 46→
 47→    return () => clearTimeout(timer);
 48→  }, []);
 49→
 50→  const animatedStyle = useAnimatedStyle(() => ({
 51→    transform: [{ translateY: translateY.value }],
 52→  }));
 53→
 54→  return (
 55→    <Animated.View style={[styles.container, animatedStyle]}>
 56→      <View style={[styles.sheet, success ? styles.successBg : styles.errorBg]}>
 57→        <Text style={styles.emoji}>{success ? '\u2705' : '\u274C'}</Text>
 58→
 59→        {success && data ? (
 60→          <>
 61→            <Text style={styles.merchantName}>{data.merchant_name}</Text>
 62→            <View style={styles.statsRow}>
 63→              {data.points_earned > 0 && (
 64→                <Text style={styles.statText}>+{data.points_earned} points</Text>
 65→              )}
 66→              {data.stamps_earned > 0 && (
 67→                <Text style={styles.statText}>+{data.stamps_earned} tampon{data.stamps_earned > 1 ? 's' : ''}</Text>
 68→              )}
 69→            </View>
 70→            <Text style={styles.totalText}>
 71→              Total : {data.total_points} pts | {data.stamps_current_card}/{data.stamps_per_card} tampons
 72→            </Text>
 73→            {data.card_completed && (
 74→              <View style={styles.completedBadge}>
 75→                <Text style={styles.completedText}>{'\uD83C\uDF89'} Carte completee ! Recompense debloquee</Text>
 76→              </View>
 77→            )}
 78→            <View style={styles.actions}>
 79→              {onViewCard && (
 80→                <Button title="Voir ma carte" onPress={onViewCard} style={{ flex: 1, marginRight: 8 }} />
 81→              )}
 82→              <Button
 83→                title="Scanner encore"
 84→                onPress={onScanAgain}
 85→                variant="outline"
 86→                style={{ flex: 1 }}
 87→              />
 88→            </View>
 89→          </>
 90→        ) : (
 91→          <>
 92→            <Text style={styles.errorTitle}>Scan echoue</Text>
 93→            <Text style={styles.errorMessage}>
 94→              {error?.message || 'Une erreur est survenue'}
 95→            </Text>
 96→            <Button title="Reessayer" onPress={onScanAgain} style={{ marginTop: 20 }} />
 97→          </>
 98→        )}
 99→      </View>
100→    </Animated.View>
101→  );
102→}
