  1→import { useState, useCallback, useRef } from 'react';
  2→import { Alert } from 'react-native';
  3→import * as Haptics from 'expo-haptics';
  4→import { supabase } from '../lib/supabase';
  5→import { parseQRUrl } from '../lib/deep-linking';
  6→import type { CustomerScanSuccessData } from '@astrolab/shared';
  7→
  8→interface ScanResult {
  9→  success: boolean;
 10→  data?: CustomerScanSuccessData;
 11→  error?: { code: string; message: string };
 12→}
 13→
 14→interface UseQRScannerResult {
 15→  isProcessing: boolean;
 16→  scanResult: ScanResult | null;
 17→  error: string | null;
 18→  flash: boolean;
 19→  toggleFlash: () => void;
 20→  handleBarCodeScanned: (data: string) => Promise<void>;
 21→  resetScan: () => void;
 22→}
 23→
 24→export function useQRScanner(): UseQRScannerResult {
 25→  const [isProcessing, setIsProcessing] = useState(false);
 26→  const [scanResult, setScanResult] = useState<ScanResult | null>(null);
 27→  const [error, setError] = useState<string | null>(null);
 28→  const [flash, setFlash] = useState(false);
 29→  const cooldownRef = useRef(false);
 30→
 31→  const toggleFlash = () => setFlash((f) => !f);
 32→
 33→  const resetScan = useCallback(() => {
 34→    setScanResult(null);
 35→    setError(null);
 36→    setIsProcessing(false);
 37→    cooldownRef.current = false;
 38→  }, []);
 39→
 40→  const handleBarCodeScanned = useCallback(async (rawData: string) => {
 41→    if (cooldownRef.current || isProcessing) return;
 42→
 43→    cooldownRef.current = true;
 44→    setIsProcessing(true);
 45→    setError(null);
 46→
 47→    // Haptic feedback
 48→    await Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
 49→
 50→    const parsed = parseQRUrl(rawData);
 51→
 52→    if (parsed.type === 'scan' && parsed.token) {
 53→      try {
 54→        const { data: { session } } = await supabase.auth.getSession();
 55→
 56→        const res = await fetch(
 57→          `${process.env.EXPO_PUBLIC_SUPABASE_URL}/functions/v1/process-customer-scan`,
 58→          {
 59→            method: 'POST',
 60→            headers: {
 61→              'Content-Type': 'application/json',
 62→              Authorization: `Bearer ${session?.access_token}`,
 63→            },
 64→            body: JSON.stringify({ token: parsed.token }),
 65→          }
 66→        );
 67→
 68→        const result = await res.json();
 69→
 70→        if (result.success) {
 71→          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
 72→          setScanResult({ success: true, data: result.data });
 73→        } else {
 74→          await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
 75→          setScanResult({ success: false, error: result.error });
 76→        }
 77→      } catch (err) {
 78→        await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
 79→        setScanResult({
 80→          success: false,
 81→          error: { code: 'NETWORK_ERROR', message: 'Erreur de connexion' },
 82→        });
 83→      }
 84→    } else if (parsed.type === 'offer' && parsed.token) {
 85→      // Offer QR - navigate to offer page
 86→      setScanResult({
 87→        success: true,
 88→        data: { offerToken: parsed.token } as unknown as CustomerScanSuccessData,
 89→      });
 90→    } else {
 91→      await Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
 92→      setError('QR code non reconnu');
 93→      setScanResult({
 94→        success: false,
 95→        error: { code: 'UNKNOWN_QR', message: 'Ce QR code n\'est pas un QR AstroLab' },
 96→      });
 97→    }
 98→
 99→    setIsProcessing(false);
100→
101→    // Reset cooldown after 3 seconds
102→    setTimeout(() => {
103→      cooldownRef.current = false;
104→    }, 3000);
105→  }, [isProcessing]);
106→
107→  return {
108→    isProcessing,
109→    scanResult,
110→    error,
111→    flash,
112→    toggleFlash,
113→    handleBarCodeScanned,
114→    resetScan,
115→  };
116→}
